Looking at the function:
```c
int ue_supported_ul_layers(NR_UE_info_t *UE_info, int CC_id)
{
  int dl_antenna_ports = UE_info->gNB_config[0].dl_antenna_ports;
  NR_ServingCellConfig_t *scc = UE_info->UE_config[CC_id].scc;
  NR_UE_NR_Capability_t *uecap = UE_info->UE_config[CC_id].uecap;
  uint8_t band = *scc->downlinkConfigCommon->initialDownlinkBWP->genericParameters.locationAndBandwidth;

  if (uecap == NULL) {
    LOG_E(MAC, "UE capability not found, defaulting to 1 layer\n");
    return 1;
  }

  // For FR1 (sub6), we currently support only 1 layer in OAI
  // This is a limitation of the current implementation
  if (band < 257) { // FR1 bands are 1-256
    LOG_D(MAC, "FR1 band detected (%d), limiting to 1 UL layer\n", band);
    return 1;
  }

  // For FR2 (mmWave), we can support more layers based on capability
  // This is a simplified check - in real implementation would check UE capabilities
  // and SRS configuration more thoroughly

  // Check UE capability for max number of layers
  if (uecap->featureSets->featureSetUplinkPerCC->list.count > 0) {
    // In a real implementation, we would check the specific UE capabilities
    // For now, we'll use a conservative approach
    int max_ue_layers = 1;
    LOG_D(MAC, "UE FR2 capability found, max layers: %d\n", max_ue_layers);
    return max_ue_layers;
  }

  // Default fallback
  LOG_W(MAC, "Could not determine UE UL layers, defaulting to 1\n");
  return 1;
}
```

